dashboard.definition:
{
  "title": "Floor Plan - Boston HQ (All Floors)",
  "description": "Meraki MT sensors, MV cameras, MR WiFi health, and Webex meeting data -- All 3 floors",
  "dataSources": {
    "ds_temp_link": {
      "type": "ds.search",
      "name": "Link Temperature",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-TEMP-LINK\" | spath path=trigger.temperature.celsius output=temp_c | timechart span=1h avg(temp_c) as count"
      }
    },
    "ds_temp_luigi": {
      "type": "ds.search",
      "name": "Luigi Temperature",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-TEMP-LUIGI\" | spath path=trigger.temperature.celsius output=temp_c | timechart span=1h avg(temp_c) as count"
      }
    },
    "ds_temp_kirby": {
      "type": "ds.search",
      "name": "Kirby Temperature",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-TEMP-KIRBY\" | spath path=trigger.temperature.celsius output=temp_c | timechart span=1h avg(temp_c) as count"
      }
    },
    "ds_temp_sonic": {
      "type": "ds.search",
      "name": "Sonic Temperature",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-TEMP-SONIC\" | spath path=trigger.temperature.celsius output=temp_c | timechart span=1h avg(temp_c) as count"
      }
    },
    "ds_temp_yoshi": {
      "type": "ds.search",
      "name": "Yoshi Temperature",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-TEMP-YOSHI\" | spath path=trigger.temperature.celsius output=temp_c | timechart span=1h avg(temp_c) as count"
      }
    },
    "ds_temp_mdf": {
      "type": "ds.search",
      "name": "MDF Temperature",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-MDF-TEMP-01\" | spath path=trigger.temperature.celsius output=temp_c | timechart span=1h avg(temp_c) as count"
      }
    },
    "ds_humid_mdf": {
      "type": "ds.search",
      "name": "MDF Humidity",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-MDF-HUMID-01\" | spath path=trigger.humidity.value output=humid | timechart span=1h avg(humid) as count"
      }
    },
    "ds_door_link": {
      "type": "ds.search",
      "name": "Link Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-DOOR-LINK\" description=\"Door opened\" | timechart span=1h count"
      }
    },
    "ds_door_luigi": {
      "type": "ds.search",
      "name": "Luigi Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-DOOR-LUIGI\" description=\"Door opened\" | timechart span=1h count"
      }
    },
    "ds_door_kirby": {
      "type": "ds.search",
      "name": "Kirby Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-DOOR-KIRBY\" description=\"Door opened\" | timechart span=1h count"
      }
    },
    "ds_door_sonic": {
      "type": "ds.search",
      "name": "Sonic Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-DOOR-SONIC\" description=\"Door opened\" | timechart span=1h count"
      }
    },
    "ds_door_yoshi": {
      "type": "ds.search",
      "name": "Yoshi Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-DOOR-YOSHI\" description=\"Door opened\" | timechart span=1h count"
      }
    },
    "ds_door_mdf": {
      "type": "ds.search",
      "name": "MDF Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-MDF-DOOR-01\" description=\"Door opened\" | timechart span=1h count"
      }
    },
    "ds_cam_boardroom_corridor": {
      "type": "ds.search",
      "name": "Boardroom Corridor Cameras",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:cameras\" (deviceName=\"CAM-BOS-3F-01\" OR deviceName=\"CAM-BOS-3F-02\") | spath type | stats count(eval(type=\"motion_detected\")) as motion, count(eval(type=\"person_detected\")) as person | eval count=motion+person"
      }
    },
    "ds_cam_mdf": {
      "type": "ds.search",
      "name": "MDF Cameras",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:cameras\" (deviceName=\"CAM-BOS-3F-03\" OR deviceName=\"CAM-BOS-3F-04\") | spath type | stats count(eval(type=\"motion_detected\")) as motion, count(eval(type=\"person_detected\")) as person | eval count=motion+person"
      }
    },
    "ds_cam_link": {
      "type": "ds.search",
      "name": "Link Camera People",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:cameras\" deviceName=\"MV-BOS-3F-LINK\" | spath type | stats count(eval(type=\"person_detected\")) as count"
      }
    },
    "ds_cam_sonic": {
      "type": "ds.search",
      "name": "Sonic Camera People",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:cameras\" deviceName=\"MV-BOS-3F-SONIC\" | spath type | stats count(eval(type=\"person_detected\")) as count"
      }
    },
    "ds_kpi_total_sensors": {
      "type": "ds.search",
      "name": "Total Sensor Events",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" (host=\"MT-BOS-3F-*\" OR host=\"MT-BOS-MDF-*\") by _time span=1h"
      }
    },
    "ds_kpi_total_sensors_count": {
      "type": "ds.search",
      "name": "Total Sensor Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" (deviceName=\"MT-BOS-3F-*\" OR deviceName=\"MT-BOS-MDF-*\") | stats count"
      }
    },
    "ds_kpi_alerts": {
      "type": "ds.search",
      "name": "Sensor Alerts Fired",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" (deviceName=\"MT-BOS-3F-*\" OR deviceName=\"MT-BOS-MDF-*\") alertFired=true | stats count"
      }
    },
    "ds_kpi_camera_events": {
      "type": "ds.search",
      "name": "Camera Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:cameras\" (deviceName=\"CAM-BOS-3F-*\" OR deviceName=\"MV-BOS-3F-*\") | stats count"
      }
    },
    "ds_kpi_door_opens": {
      "type": "ds.search",
      "name": "Total Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" (deviceName=\"MT-BOS-3F-DOOR-*\" OR deviceName=\"MT-BOS-MDF-DOOR-*\") description=\"Door opened\" | stats count"
      }
    },
    "ds_temp_timeline": {
      "type": "ds.search",
      "name": "Room Temperatures Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-3F-TEMP-*\" | spath path=trigger.temperature.celsius output=temp_c | spath path=sensor.name output=room | timechart span=1h avg(temp_c) by room"
      }
    },
    "ds_door_timeline": {
      "type": "ds.search",
      "name": "Door Opens Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" (deviceName=\"MT-BOS-3F-DOOR-*\" OR deviceName=\"MT-BOS-MDF-DOOR-*\") description=\"Door opened\" | spath path=sensor.name output=room | timechart span=1h count by room"
      }
    },
    "ds_motion_timeline": {
      "type": "ds.search",
      "name": "Camera Motion Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:cameras\" (deviceName=\"CAM-BOS-3F-*\" OR deviceName=\"MV-BOS-3F-*\") type=\"motion_detected\" | spath path=eventData.area output=area | timechart span=1h count by area"
      }
    },
    "ds_alert_table": {
      "type": "ds.search",
      "name": "Recent Sensor Alerts",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" (deviceName=\"MT-BOS-3F-*\" OR deviceName=\"MT-BOS-MDF-*\") alertFired=true | spath path=sensor.name output=room | spath path=trigger.metric output=metric | spath path=trigger.temperature.celsius output=temp_c | table _time deviceName room metric temp_c | sort -_time | head 20 | rename deviceName as \"Sensor\" room as \"Room\" metric as \"Metric\" temp_c as \"Temp (C)\""
      }
    },
    "ds_wifi_3f01": {
      "type": "ds.search",
      "name": "AP-BOS-3F-01 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-3F-01\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_wifi_3f02": {
      "type": "ds.search",
      "name": "AP-BOS-3F-02 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-3F-02\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_wifi_3f03": {
      "type": "ds.search",
      "name": "AP-BOS-3F-03 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-3F-03\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_wifi_3f04": {
      "type": "ds.search",
      "name": "AP-BOS-3F-04 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-3F-04\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_wifi_3f05": {
      "type": "ds.search",
      "name": "AP-BOS-3F-05 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-3F-05\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_wifi_3f06": {
      "type": "ds.search",
      "name": "AP-BOS-3F-06 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-3F-06\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_kpi_avg_wifi": {
      "type": "ds.search",
      "name": "Avg WiFi Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-3F-*\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as health by deviceName | stats avg(health) as count | eval count=round(count,0)"
      }
    },
    "ds_mtg_link": {
      "type": "ds.search",
      "name": "Link Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingattendeehistory\" clientType=\"Telepresence\" attendeeName=\"WEBEX-BOS-3F-LINK\" | stats dc(confID) as meetings, avg(duration) as avg_dur | eval count=meetings.\" mtg (\".round(avg_dur,0).\" min avg)\""
      }
    },
    "ds_mtg_luigi": {
      "type": "ds.search",
      "name": "Luigi Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingattendeehistory\" clientType=\"Telepresence\" attendeeName=\"WEBEX-BOS-3F-LUIGI\" | stats dc(confID) as meetings, avg(duration) as avg_dur | eval count=meetings.\" mtg (\".round(avg_dur,0).\" min avg)\""
      }
    },
    "ds_mtg_kirby": {
      "type": "ds.search",
      "name": "Kirby Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingattendeehistory\" clientType=\"Telepresence\" attendeeName=\"WEBEX-BOS-3F-KIRBY\" | stats dc(confID) as meetings, avg(duration) as avg_dur | eval count=meetings.\" mtg (\".round(avg_dur,0).\" min avg)\""
      }
    },
    "ds_mtg_sonic": {
      "type": "ds.search",
      "name": "Sonic Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingattendeehistory\" clientType=\"Telepresence\" attendeeName=\"WEBEX-BOS-3F-SONIC\" | stats dc(confID) as meetings, avg(duration) as avg_dur | eval count=meetings.\" mtg (\".round(avg_dur,0).\" min avg)\""
      }
    },
    "ds_mtg_yoshi": {
      "type": "ds.search",
      "name": "Yoshi Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingattendeehistory\" clientType=\"Telepresence\" attendeeName=\"WEBEX-BOS-3F-YOSHI\" | stats dc(confID) as meetings, avg(duration) as avg_dur | eval count=meetings.\" mtg (\".round(avg_dur,0).\" min avg)\""
      }
    },
    "ds_wifi_health_timeline": {
      "type": "ds.search",
      "name": "WiFi Health Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-3F-*\" | spath path=eventData.healthScore.performance output=health | timechart span=1h avg(health) by area"
      }
    },
    "ds_mtg_room_timeline": {
      "type": "ds.search",
      "name": "Meetings by Room Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingattendeehistory\" clientType=\"Telepresence\" attendeeName IN (\"WEBEX-BOS-3F-LINK\",\"WEBEX-BOS-3F-LUIGI\",\"WEBEX-BOS-3F-KIRBY\",\"WEBEX-BOS-3F-SONIC\",\"WEBEX-BOS-3F-YOSHI\") | eval room=replace(attendeeName,\"WEBEX-BOS-\\\\d+F-\",\"\") | timechart span=1d dc(confID) by room"
      }
    },
    "ds_f2_temp_zelda": {
      "type": "ds.search",
      "name": "F2 Zelda Temperature",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-TEMP-ZELDA\" | spath path=trigger.temperature.celsius output=temp_c | timechart span=1h avg(temp_c) as count"
      }
    },
    "ds_f2_temp_samus": {
      "type": "ds.search",
      "name": "F2 Samus Temperature",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-TEMP-SAMUS\" | spath path=trigger.temperature.celsius output=temp_c | timechart span=1h avg(temp_c) as count"
      }
    },
    "ds_f2_temp_mario": {
      "type": "ds.search",
      "name": "F2 Mario Temperature",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-TEMP-MARIO\" | spath path=trigger.temperature.celsius output=temp_c | timechart span=1h avg(temp_c) as count"
      }
    },
    "ds_f2_door_zelda": {
      "type": "ds.search",
      "name": "F2 Zelda Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-DOOR-ZELDA\" description=\"Door opened\" | timechart span=1h count"
      }
    },
    "ds_f2_door_samus": {
      "type": "ds.search",
      "name": "F2 Samus Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-DOOR-SAMUS\" description=\"Door opened\" | timechart span=1h count"
      }
    },
    "ds_f2_door_mario": {
      "type": "ds.search",
      "name": "F2 Mario Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-DOOR-MARIO\" description=\"Door opened\" | timechart span=1h count"
      }
    },
    "ds_f2_wifi_01": {
      "type": "ds.search",
      "name": "F2 AP-BOS-2F-01 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-2F-01\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_f2_wifi_02": {
      "type": "ds.search",
      "name": "F2 AP-BOS-2F-02 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-2F-02\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_f2_wifi_03": {
      "type": "ds.search",
      "name": "F2 AP-BOS-2F-03 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-2F-03\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_f2_wifi_04": {
      "type": "ds.search",
      "name": "F2 AP-BOS-2F-04 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-2F-04\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_f2_wifi_05": {
      "type": "ds.search",
      "name": "F2 AP-BOS-2F-05 Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-2F-05\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as count"
      }
    },
    "ds_f2_kpi_avg_wifi": {
      "type": "ds.search",
      "name": "F2 Avg WiFi Health",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-2F-*\" | spath path=eventData.healthScore.performance output=health | stats latest(health) as health by deviceName | stats avg(health) as count | eval count=round(count,0)"
      }
    },
    "ds_f2_mtg_zelda": {
      "type": "ds.search",
      "name": "F2 Zelda Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingattendeehistory\" clientType=\"Telepresence\" attendeeName=\"WEBEX-BOS-2F-ZELDA\" | stats dc(confID) as meetings, avg(duration) as avg_dur | eval count=meetings.\" mtg (\".round(avg_dur,0).\" min avg)\""
      }
    },
    "ds_f2_mtg_samus": {
      "type": "ds.search",
      "name": "F2 Samus Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingattendeehistory\" clientType=\"Telepresence\" attendeeName=\"WEBEX-BOS-2F-SAMUS\" | stats dc(confID) as meetings, avg(duration) as avg_dur | eval count=meetings.\" mtg (\".round(avg_dur,0).\" min avg)\""
      }
    },
    "ds_f2_mtg_mario": {
      "type": "ds.search",
      "name": "F2 Mario Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingattendeehistory\" clientType=\"Telepresence\" attendeeName=\"WEBEX-BOS-2F-MARIO\" | stats dc(confID) as meetings, avg(duration) as avg_dur | eval count=meetings.\" mtg (\".round(avg_dur,0).\" min avg)\""
      }
    },
    "ds_f2_kpi_sensors": {
      "type": "ds.search",
      "name": "F2 Total Sensor Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-*\" | stats count"
      }
    },
    "ds_f2_kpi_alerts": {
      "type": "ds.search",
      "name": "F2 Sensor Alerts",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-*\" alertFired=true | stats count"
      }
    },
    "ds_f2_kpi_doors": {
      "type": "ds.search",
      "name": "F2 Total Door Opens",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-DOOR-*\" description=\"Door opened\" | stats count"
      }
    },
    "ds_f2_temp_timeline": {
      "type": "ds.search",
      "name": "F2 Room Temperatures Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-TEMP-*\" | spath path=trigger.temperature.celsius output=temp_c | spath path=sensor.name output=room | timechart span=1h avg(temp_c) by room"
      }
    },
    "ds_f2_door_timeline": {
      "type": "ds.search",
      "name": "F2 Door Opens Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:sensors\" deviceName=\"MT-BOS-2F-DOOR-*\" description=\"Door opened\" | spath path=sensor.name output=room | timechart span=1h count by room"
      }
    },
    "ds_f2_wifi_health_timeline": {
      "type": "ds.search",
      "name": "F2 WiFi Health Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:meraki:accesspoints:health\" deviceName=\"AP-BOS-2F-*\" | spath path=eventData.healthScore.performance output=health | timechart span=1h avg(health) by area"
      }
    },
    "ds_f2_mtg_room_timeline": {
      "type": "ds.search",
      "name": "F2 Meetings by Room Over Time",
      "options": {
